def overlap(al, ar, bl, br):
    return max(0, min(ar, br) - max(al, bl) + 1)

def compute_max(la, ra, ta, lb, rb, tb):
    g = gcd(ta, tb)
    max_len = 0
    len_a = ra - la + 1
    len_b = rb - lb + 1

    # The key idea is to check the overlaps around the closest k where the segments can overlap
    # We need to check k around the optimal positions without iterating all possible k

    # The possible k's are around (lb - la) / g and similar
    k0 = (lb - la) // g
    for k in [k0 - 1, k0, k0 + 1]:
        a_l = la + k * g
        a_r = a_l + len_a - 1
        current_overlap = overlap(a_l, a_r, lb, rb)
